     */
    fun `startSession`(`theirIdentityKey`: kotlin.String, `theirOneTimeKey`: kotlin.String): Session
    
    /**
     * Encrypted pickle to persist this identity in device storage.
     */
    fun `toPickle`(`pickleKey`: kotlin.ByteArray): kotlin.String
    
    companion object
}

