    protected val handle: Long
    protected val cleanable: UniffiCleaner.Cleanable?

    private val wasDestroyed = AtomicBoolean(false)
    private val callCounter = AtomicLong(1)

    override fun destroy() {
        // Only allow a single call to this method.
        // TODO: maybe we should log a warning if called more than once?
        if (this.wasDestroyed.compareAndSet(false, true)) {
            // This decrement always matches the initial count of 1 given at creation time.
            if (this.callCounter.decrementAndGet() == 0L) {
                cleanable?.clean()
            }
        }
    }

    @Synchronized
    override fun close() {
        this.destroy()
    }

    internal inline fun <R> callWithHandle(block: (handle: Long) -> R): R {
        // Check and increment the call counter, to keep the object alive.
        // This needs a compare-and-set retry loop in case of concurrent updates.
        do {
            val c = this.callCounter.get()
            if (c == 0L) {
                throw IllegalStateException("${this.javaClass.simpleName} object has already been destroyed")
            }
            if (c == Long.MAX_VALUE) {
                throw IllegalStateException("${this.javaClass.simpleName} call counter would overflow")
            }
        } while (! this.callCounter.compareAndSet(c, c + 1L))
        // Now we can safely do the method call without the handle being freed concurrently.
        try {
            return block(this.uniffiCloneHandle())
        } finally {
            // This decrement always matches the increment we performed above.
            if (this.callCounter.decrementAndGet() == 0L) {
                cleanable?.clean()
            }
        }
    }

    // Use a static inner class instead of a closure so as not to accidentally
    // capture `this` as part of the cleanable's action.
    private class UniffiCleanAction(private val handle: Long) : Runnable {
        override fun run() {
            if (handle == 0.toLong()) {
                // Fake object created with `NoHandle`, don't try to free.
                return;
            }
            uniffiRustCall { status ->
                UniffiLib.uniffi_voiid_e2e_core_fn_free_session(handle, status)
            }
        }
    }

    /**
     * @suppress
     */
    fun uniffiCloneHandle(): Long {
        if (handle == 0.toLong()) {
            throw InternalException("uniffiCloneHandle() called on NoHandle object");
        }
        return uniffiRustCall() { status ->
            UniffiLib.uniffi_voiid_e2e_core_fn_clone_session(handle, status)
        }
    }

    
    @Throws(E2eFfiException::class)override fun `decrypt`(`message`: WireMessage): kotlin.ByteArray {
            return FfiConverterByteArray.lift(
    callWithHandle {
    uniffiRustCallWithError(E2eFfiException) { _status ->
    UniffiLib.uniffi_voiid_e2e_core_fn_method_session_decrypt(
        it,
        FfiConverterTypeWireMessage.lower(`message`),_status)
}
    }
    )
    }
    

    
    @Throws(E2eFfiException::class)override fun `encrypt`(`plaintext`: kotlin.ByteArray): WireMessage {
            return FfiConverterTypeWireMessage.lift(
    callWithHandle {
    uniffiRustCallWithError(E2eFfiException) { _status ->
    UniffiLib.uniffi_voiid_e2e_core_fn_method_session_encrypt(
        it,
        FfiConverterByteArray.lower(`plaintext`),_status)
}
    }
    )
    }
    

    
    @Throws(E2eFfiException::class)override fun `toPickle`(`pickleKey`: kotlin.ByteArray): kotlin.String {
            return FfiConverterString.lift(
    callWithHandle {
    uniffiRustCallWithError(E2eFfiException) { _status ->
    UniffiLib.uniffi_voiid_e2e_core_fn_method_session_to_pickle(
        it,
        FfiConverterByteArray.lower(`pickleKey`),_status)
}
    }
    )
    }
    

    

    


    
    companion object {
        
    @Throws(E2eFfiException::class) fun `restore`(`pickle`: kotlin.String, `pickleKey`: kotlin.ByteArray): Session {
            return FfiConverterTypeSession.lift(
    uniffiRustCallWithError(E2eFfiException) { _status ->
    UniffiLib.uniffi_voiid_e2e_core_fn_constructor_session_restore(
    
        FfiConverterString.lower(`pickle`),FfiConverterByteArray.lower(`pickleKey`),_status)
}
    )
    }
    

        
    }
    
}


/**
 * @suppress
 */
public object FfiConverterTypeSession: FfiConverter<Session, Long> {
    override fun lower(value: Session): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): Session {
        return Session(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): Session {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: Session) = 8UL

    override fun write(value: Session, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



/**
