data class AcceptedSession (
    var `session`: Session
    , 
    var `plaintext`: kotlin.ByteArray
    
): Disposable{
    

    

    
    @Suppress("UNNECESSARY_SAFE_CALL") // codegen is much simpler if we unconditionally emit safe calls here
    override fun destroy() {
        
    Disposable.destroy(
        this.`session`,
        this.`plaintext`
    )
    }
    
    companion object
}

/**
