/**
 * Flat error surfaced to Swift/Kotlin. No secrets in any variant.
 */
sealed class E2eFfiException: kotlin.Exception() {
    
    class NoSession(
        ) : E2eFfiException() {
        override val message
            get() = ""
    }
    
    class DecryptionFailed(
        ) : E2eFfiException() {
        override val message
            get() = ""
    }
    
    class InvalidKey(
        ) : E2eFfiException() {
        override val message
            get() = ""
    }
    
    class Serialization(
        ) : E2eFfiException() {
        override val message
            get() = ""
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<E2eFfiException> {
        override fun lift(error_buf: RustBuffer.ByValue): E2eFfiException = FfiConverterTypeE2eFfiError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeE2eFfiError : FfiConverterRustBuffer<E2eFfiException> {
    override fun read(buf: ByteBuffer): E2eFfiException {
        

        return when(buf.getInt()) {
            1 -> E2eFfiException.NoSession()
            2 -> E2eFfiException.DecryptionFailed()
            3 -> E2eFfiException.InvalidKey()
            4 -> E2eFfiException.Serialization()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: E2eFfiException): ULong {
        return when(value) {
            is E2eFfiException.NoSession -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is E2eFfiException.DecryptionFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is E2eFfiException.InvalidKey -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is E2eFfiException.Serialization -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: E2eFfiException, buf: ByteBuffer) {
        when(value) {
            is E2eFfiException.NoSession -> {
                buf.putInt(1)
                Unit
            }
            is E2eFfiException.DecryptionFailed -> {
                buf.putInt(2)
                Unit
            }
            is E2eFfiException.InvalidKey -> {
                buf.putInt(3)
                Unit
            }
            is E2eFfiException.Serialization -> {
                buf.putInt(4)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




/**
 * @suppress
 */
public object FfiConverterOptionalByteArray: FfiConverterRustBuffer<kotlin.ByteArray?> {
    override fun read(buf: ByteBuffer): kotlin.ByteArray? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterByteArray.read(buf)
    }

    override fun allocationSize(value: kotlin.ByteArray?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterByteArray.allocationSize(value)
        }
    }

    override fun write(value: kotlin.ByteArray?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterByteArray.write(value, buf)
        }
    }
}




/**
 * @suppress
 */
public object FfiConverterSequenceString: FfiConverterRustBuffer<List<kotlin.String>> {
    override fun read(buf: ByteBuffer): List<kotlin.String> {
        val len = buf.getInt()
        return List<kotlin.String>(len) {
            FfiConverterString.read(buf)
        }
    }

    override fun allocationSize(value: List<kotlin.String>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterString.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

    override fun write(value: List<kotlin.String>, buf: ByteBuffer) {
        buf.putInt(value.size)
        value.iterator().forEach {
            FfiConverterString.write(it, buf)
        }
    }
}
